#include<iostream>#include<vector>#include<algorithm>#include<cmath>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        ll k=1;        ll temp= n;        for( ll i=2;i*i<=temp;i++){            if(temp%i==0){                k*=i;                while(temp%i==0){                    temp/=i;                }            }        }        if(temp>1){            k*=temp;        }        cout<<k<<"\n";            }}